'use client';

import * as React from 'react';
import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { cn } from '@/lib/utils';

// ─── Types ────────────────────────────────────────────────────────────────────

export interface MasonryImage {
  src: string;
  alt?: string;
  /** Natural width hint — skips waiting for onLoad if provided */
  width?: number;
  /** Natural height hint — skips waiting for onLoad if provided */
  height?: number;
  /** Arbitrary metadata you want back in callbacks */
  id?: string | number;
}

export interface MasonryFeedProps {
  images: MasonryImage[];
  /** Number of columns */
  columns?: number;
  /** Gap between items in px */
  gap?: number;
  /** Border radius on each image card in px */
  radius?: number;
  /** Called when an image is clicked */
  onImageClick?: (image: MasonryImage, index: number) => void;
  /** Overlay element rendered on hover over each image */
  renderOverlay?: (image: MasonryImage, index: number) => React.ReactNode;
  /** Shown while images are still measuring */
  loadingPlaceholder?: React.ReactNode;
  className?: string;
}

// ─── Layout engine ────────────────────────────────────────────────────────────

interface LayoutItem {
  image: MasonryImage;
  index: number;
  top: number;
  left: number;
  width: number;
  height: number;
}

function computeLayout(
  images: MasonryImage[],
  containerWidth: number,
  columns: number,
  gap: number,
  ratios: Record<string, number> // src → h/w ratio
): { items: LayoutItem[]; totalHeight: number } {
  if (containerWidth === 0 || images.length === 0) {
    return { items: [], totalHeight: 0 };
  }

  const colWidth = (containerWidth - gap * (columns - 1)) / columns;
  const colHeights = new Array<number>(columns).fill(0);

  const items: LayoutItem[] = [];

  for (let i = 0; i < images.length; i++) {
    const img = images[i];
    const ratio = ratios[img.src];

    // If we don't know the ratio yet, skip — we'll re-run after measurement
    if (ratio === undefined) continue;

    // ← left-to-right: find shortest column
    let shortestCol = 0;
    let shortestHeight = colHeights[0];
    for (let c = 1; c < columns; c++) {
      if (colHeights[c] < shortestHeight) {
        shortestHeight = colHeights[c];
        shortestCol = c;
      }
    }

    const top =
      colHeights[shortestCol] === 0 ? colHeights[shortestCol] : colHeights[shortestCol] + gap;
    const left = shortestCol * (colWidth + gap);
    const height = colWidth * ratio;

    items.push({ image: img, index: i, top, left, width: colWidth, height });
    colHeights[shortestCol] = top + height;
  }

  return { items, totalHeight: Math.max(...colHeights) };
}

// ─── Invisible probe to measure unknown image ratios ─────────────────────────

function ImageProbe({
  src,
  onMeasured,
}: {
  src: string;
  onMeasured: (src: string, ratio: number) => void;
}) {
  return (
    // eslint-disable-next-line @next/next/no-img-element
    <img
      src={src}
      alt=""
      aria-hidden
      onLoad={(e) => {
        const el = e.currentTarget;
        if (el.naturalWidth > 0) {
          onMeasured(src, el.naturalHeight / el.naturalWidth);
        }
      }}
      style={{
        position: 'absolute',
        width: 1,
        height: 1,
        opacity: 0,
        pointerEvents: 'none',
        visibility: 'hidden',
      }}
    />
  );
}

// ─── Single masonry card ──────────────────────────────────────────────────────

function MasonryCard({
  item,
  radius,
  onClick,
  renderOverlay,
}: {
  item: LayoutItem;
  radius: number;
  onClick?: () => void;
  renderOverlay?: (image: MasonryImage, index: number) => React.ReactNode;
}) {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      role={onClick ? 'button' : undefined}
      tabIndex={onClick ? 0 : undefined}
      onKeyDown={onClick ? (e) => e.key === 'Enter' && onClick() : undefined}
      onClick={onClick}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        position: 'absolute',
        top: item.top,
        left: item.left,
        width: item.width,
        height: item.height,
        borderRadius: radius,
        overflow: 'hidden',
        cursor: onClick ? 'pointer' : 'default',
        // subtle transition for when layout re-runs
        transition: 'top 0.3s ease, left 0.3s ease, width 0.3s ease, height 0.3s ease',
      }}
    >
      {/* eslint-disable-next-line @next/next/no-img-element */}
      <img
        src={item.image.src}
        alt={item.image.alt ?? ''}
        draggable={false}
        style={{
          width: '100%',
          height: '100%',
          objectFit: 'cover',
          display: 'block',
          userSelect: 'none',
        }}
      />

      {/* Hover overlay */}
      {renderOverlay && (
        <div
          style={{
            position: 'absolute',
            inset: 0,
            opacity: hovered ? 1 : 0,
            transition: 'opacity 0.2s ease',
            pointerEvents: hovered ? 'auto' : 'none',
          }}
        >
          {renderOverlay(item.image, item.index)}
        </div>
      )}
    </div>
  );
}

// ─── Main component ───────────────────────────────────────────────────────────

export function MasonryFeed({
  images,
  columns = 3,
  gap = 12,
  radius = 12,
  onImageClick,
  renderOverlay,
  loadingPlaceholder,
  className,
}: MasonryFeedProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [containerWidth, setContainerWidth] = useState(0);
  const [ratios, setRatios] = useState<Record<string, number>>(() => {
    // Pre-seed ratios from provided width/height hints
    const seed: Record<string, number> = {};
    for (const img of images) {
      if (img.width && img.height && img.width > 0) {
        seed[img.src] = img.height / img.width;
      }
    }
    return seed;
  });

  // Observe container width
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const ro = new ResizeObserver(([entry]) => {
      setContainerWidth(entry.contentRect.width);
    });
    ro.observe(el);
    setContainerWidth(el.getBoundingClientRect().width);
    return () => ro.disconnect();
  }, []);

  const handleMeasured = useCallback((src: string, ratio: number) => {
    setRatios((prev) => {
      if (prev[src] === ratio) return prev;
      return { ...prev, [src]: ratio };
    });
  }, []);

  const unknownSrcs = useMemo(
    () => images.filter((img) => ratios[img.src] === undefined).map((img) => img.src),
    [images, ratios]
  );

  const { items, totalHeight } = useMemo(
    () => computeLayout(images, containerWidth, columns, gap, ratios),
    [images, containerWidth, columns, gap, ratios]
  );

  const allMeasured = unknownSrcs.length === 0;
  const hasItems = items.length > 0;

  return (
    <div ref={containerRef} className={cn('w-full', className)}>
      {/* Invisible probes for unmeasured images */}
      {unknownSrcs.map((src) => (
        <ImageProbe key={src} src={src} onMeasured={handleMeasured} />
      ))}

      {/* Loading state */}
      {!hasItems && !allMeasured && (
        <div>
          {loadingPlaceholder ?? (
            <div className="text-muted-foreground flex items-center justify-center py-16 font-mono text-xs tracking-widest uppercase">
              loading…
            </div>
          )}
        </div>
      )}

      {/* Masonry canvas */}
      {hasItems && (
        <div
          style={{
            position: 'relative',
            width: '100%',
            height: totalHeight,
          }}
        >
          {items.map((item) => (
            <MasonryCard
              key={`${item.image.src}-${item.index}`}
              item={item}
              radius={radius}
              onClick={onImageClick ? () => onImageClick(item.image, item.index) : undefined}
              renderOverlay={renderOverlay}
            />
          ))}
        </div>
      )}
    </div>
  );
}
